Database error handling and recovery for SQLite operations. When a SQLITE_BUSY timeout occurs, this handler implements retry logic with exponential backoff to recover from temporary failures.

fn handle_sqlite_error(err: SqliteError) -> DbResult {
    match err.code() {
        SQLITE_BUSY => {
            warn!("SQLITE_BUSY timeout - retrying");
            Err(DbError::Retry)
        }
        _ => Err(DbError::Fatal(err))
    }
}

