Request validation middleware for HTTP requests. Validates incoming requests against schema definitions to ensure API contract compliance before processing.

pub async fn validate_request<T: DeserializeOwned + Validate>(
    req: Request<Body>
) -> Result<T, ValidationError> {
    let body: T = parse_body(req).await?;
    body.validate()?;
    Ok(body)
}

Middleware function for request validation that ensures all incoming HTTP requests meet the API contract specifications. Returns validation errors for invalid requests.

function validateRequestMiddleware(schema) {
    return async (req, res, next) => {
        const { error, value } = schema.validate(req.body);
        if (error) {
            return res.status(400).json({ error: error.details });
        }
        req.validatedBody = value;
        next();
    };
}
